  -moz-osx-font-smoothing: grayscale;
}

/* ==================== 主按钮：蓝色渐变 ==================== */
.ant-btn-primary:not(.ant-btn-dangerous):not(:disabled):not(.ant-btn-background-ghost):not(.ant-btn-link) {
  background: linear-gradient(135deg, #4E8CFF 0%, #2B6BE5 100%) !important;
  border: none !important;
  box-shadow: 0 2px 4px rgba(43, 107, 229, 0.20);
  transition: all 0.2s cubic-bezier(0.4, 0, 0.2, 1);
}

.ant-btn-primary:not(.ant-btn-dangerous):not(:disabled):not(.ant-btn-background-ghost):not(.ant-btn-link):hover {
  background: linear-gradient(135deg, #5B97FF 0%, #3578EF 100%) !important;
  box-shadow: 0 4px 12px rgba(43, 107, 229, 0.28);
  transform: translateY(-1px);
}

.ant-btn-primary:not(.ant-btn-dangerous):not(:disabled):not(.ant-btn-background-ghost):not(.ant-btn-link):active {
  background: linear-gradient(135deg, #3D7EFF 0%, #1E5AD1 100%) !important;
  box-shadow: 0 1px 2px rgba(43, 107, 229, 0.24);
  transform: translateY(0);
}

.ant-btn-primary:disabled,
.ant-btn-primary[disabled] {
  background: #F2F4F7 !important;
  color: #98A2B3 !important;
  box-shadow: none !important;
}

